#include<bits/stdc++.h>using namespace std; int t,n,ct;int const N=1e5+5;int a[N],vis[N];void dfs(int x){  if(x==n+1){    ct++;    for(int i=1;i<=n;i++)cout<< a[i] << " ";    cout<< "\n";  }  if(ct==n)return;  for(int i=1;i<=n;i++){    if(a[x-2]+a[x-1]==i)continue;    if(vis[i])continue;    vis[i]=1;    a[x]=i;    dfs(x+1);    vis[i]=0;  }}void slove(){  ct=0;  cin>> n;  dfs(1);}int main(){  cin>> t;  while(t--)slove();  return 0;}